sql:
SELECT AVG(aircraft.wing_span) AS average_wingspan
FROM aircraft
WHERE aircraft.year_built < '1950' AND aircraft.current_condition = 'operational';

SELECT a.number_and_name
FROM aircraft a
WHERE a.range = (SELECT MAX(range) FROM aircraft);

SELECT number_and_name
FROM aircraft
WHERE range = (SELECT MAX(range) FROM aircraft);

SELECT DISTINCT class
FROM aircraft
ORDER BY class;

external_knowledge:
- "Specifications" here refers to the physical and performance characteristics of an aircraft;
- "Operational status" indicates whether an aircraft is currently operational, non-operational, or under restoration;
- "Restoration status" refers to the completion status of the aircraft's restoration process;
- "Historical significance" encompasses notable events, their years, and descriptions that are important to the aircraft's history.

sql:
SELECT
    class,
    SUM(range) OVER (PARTITION BY class ORDER BY aircraft_id) AS cumulative_range
FROM
    aircraft
WHERE
    class IS NOT NULL
ORDER BY
    class,
    cumulative_range;

SELECT builder_name 
FROM builders 
WHERE builder_id = 101;

SELECT number_and_name
FROM aircraft
WHERE max_speed = (
    SELECT MAX(max_speed)
    FROM aircraft
) AND year_built = (
    SELECT MIN(year_built)
    FROM aircraft
);

SELECT number_and_name
FROM aircraft
WHERE max_speed = (SELECT MAX(max_speed) FROM aircraft);

SELECT number_and_name, class, max_speed
FROM aircraft
WHERE max_speed = (
    SELECT MAX(max_speed)
    FROM aircraft
);
